const result = [];

for (const item of $input.all()) {
  const templates = item.json.templates || [];

  for (const t of templates) {
    result.push({
      json: {
        pageContent: `Template: ${t.name}
Description: ${t.description}
Use cases: ${(t.use_case || []).join(', ')}
Apps: ${(t.apps || []).join(', ')}
Difficulty: ${t.difficulty}
Setup notes: ${t.setup_notes || ''}`,
        metadata: {
          name: t.name,
          difficulty: t.difficulty,
          apps: t.apps || [],
          use_case: t.use_case || [],
          categories: t.categories || [],
          tags: t.tags || []
        }
      }
    });
  }
}

return result;

return items.map(item => {
  const d = item.json;
  return {
    json: {
      pageContent: [
        "Template: " + (d.name || ''),
        "Description: " + (d.description || ''),
        "Use cases: " + (d.use_case ? d.use_case.join(', ') : ''),
        "Apps: " + (d.apps ? d.apps.join(', ') : ''),
        "Difficulty: " + (d.difficulty || '')
      ].join('\n'),
      metadata: {
        template_id: d.id,
        template_url: "https://n8n.io/workflows/" + d.id,
        name: d.name || '',
        views: d.totalViews || 0
      }
    }
  };
});
